code:
type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function rangeArray(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${stepStr}"`);

    let from: number;
    let to: number;

    if (rangePart === "*") {
      from = min;
      to = max;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      from = parseInt(startStr, 10);
      to = parseInt(endStr, 10);
      if (isNaN(from) || isNaN(to)) throw new Error(`Invalid step range: "${rangePart}"`);
      assertInRange(from, min, max, segment);
      assertInRange(to, min, max, segment);
    } else {
      from = parseInt(rangePart, 10);
      if (isNaN(from)) throw new Error(`Invalid step base: "${rangePart}"`);
      assertInRange(from, min, max, segment);
      to = max;
    }

    const result: number[] = [];
    for (let v = from; v <= to; v += step) result.push(v);
    return result;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const from = parseInt(startStr, 10);
    const to = parseInt(endStr, 10);
    if (isNaN(from) || isNaN(to)) throw new Error(`Invalid range: "${segment}"`);
    assertInRange(from, min, max, segment);
    assertInRange(to, min, max, segment);
    return rangeArray(from, to);
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Literal number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron value: "${segment}"`);
  assertInRange(value, min, max, segment);
  return [value];
}

function parseField(field: string, fieldName: FieldName): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  const segments = field.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max);
    for (const v of parsed) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${parts.length}: "${expression}"`);
  }

  return Object.fromEntries(
    FIELD_ORDER.map((fieldName, i) => [fieldName, parseField(parts[i], fieldName)])
  ) as CronFields;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function mergeInternal(
  target: unknown,
  source: unknown,
  visiting: WeakSet<object>
): unknown {
  // Both arrays → concatenate (guard: source is not null, arrays are objects)
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  // Both plain objects → merge recursively
  if (isPlainObject(target) && isPlainObject(source)) {
    // Detect circular references in source to prevent infinite recursion
    if (visiting.has(source)) {
      return source;
    }

    visiting.add(source);

    const result: PlainObject = Object.assign(Object.create(null), target);

    for (const key of Object.keys(source)) {
      // Reject prototype-poisoning keys unconditionally
      if (UNSAFE_KEYS.has(key)) continue;

      result[key] = mergeInternal(
        Object.prototype.hasOwnProperty.call(target, key) ? target[key] : undefined,
        source[key],
        visiting
      );
    }

    visiting.delete(source);

    return result;
  }

  // Primitives, class instances, mismatched types → source wins
  // Exception: if source is undefined, preserve target
  return source === undefined ? target : source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  return mergeInternal(target, source, new WeakSet()) as T & S;
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) {
      throw new Error("Capacity must be a positive integer");
    }
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) {
      return undefined;
    }
    const value = this.map.get(key)!;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): ReturnType<T> | undefined;
  cancel(): void;
  flush(): ReturnType<T> | undefined;
};

function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let lastResult: ReturnType<T> | undefined;

  const invoke = (): ReturnType<T> => {
    const args = pendingArgs!;
    pendingArgs = undefined;
    lastResult = fn(...args) as ReturnType<T>;
    return lastResult;
  };

  const debounced = (...args: Parameters<T>): ReturnType<T> | undefined => {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      invoke();
    }, delay);

    return lastResult;
  };

  debounced.cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = (): ReturnType<T> | undefined => {
    if (timerId === undefined || pendingArgs === undefined) {
      return lastResult;
    }

    clearTimeout(timerId);
    timerId = undefined;

    return invoke();
  };

  return debounced;
}

export default debounce;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? { ...source } : source ?? target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: ReadonlyArray<FieldConfig> = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
];

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const slashParts = segment.split("/");

  if (slashParts.length > 2) {
    throw new Error(
      `Invalid segment "${segment}" in field "${fieldName}": multiple slashes are not permitted`
    );
  }

  const hasStep = slashParts.length === 2;
  let step = 1;

  if (hasStep) {
    const stepStr = slashParts[1];
    if (!/^\d+$/.test(stepStr)) {
      throw new Error(
        `Invalid step value "${stepStr}" in field "${fieldName}": must be a positive integer`
      );
    }
    step = parseInt(stepStr, 10);
    if (step < 1) {
      throw new Error(
        `Invalid step value ${step} in field "${fieldName}": step must be >= 1`
      );
    }
  }

  const rangeStr = slashParts[0];
  let rangeMin: number;
  let rangeMax: number;

  if (rangeStr === "*") {
    rangeMin = min;
    rangeMax = max;
  } else if (rangeStr.includes("-")) {
    const dashParts = rangeStr.split("-");
    if (dashParts.length !== 2) {
      throw new Error(
        `Invalid range "${rangeStr}" in field "${fieldName}": expected format "start-end"`
      );
    }
    const [startStr, endStr] = dashParts;
    if (!/^\d+$/.test(startStr)) {
      throw new Error(
        `Invalid range start "${startStr}" in field "${fieldName}": must be a non-negative integer`
      );
    }
    if (!/^\d+$/.test(endStr)) {
      throw new Error(
        `Invalid range end "${endStr}" in field "${fieldName}": must be a non-negative integer`
      );
    }
    rangeMin = parseInt(startStr, 10);
    rangeMax = parseInt(endStr, 10);
    if (rangeMin > rangeMax) {
      throw new Error(
        `Invalid range "${rangeStr}" in field "${fieldName}": start (${rangeMin}) must be <= end (${rangeMax})`
      );
    }
  } else {
    if (!/^\d+$/.test(rangeStr)) {
      throw new Error(
        `Invalid value "${rangeStr}" in field "${fieldName}": must be a non-negative integer or "*"`
      );
    }
    rangeMin = parseInt(rangeStr, 10);
    // "N/step" means starting at N, every step, up to field max (e.g. "5/15" in minutes → 5,20,35,50)
    rangeMax = hasStep ? max : rangeMin;
  }

  if (rangeMin < min || rangeMin > max) {
    throw new Error(
      `Value ${rangeMin} is out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }
  if (rangeMax > max) {
    throw new Error(
      `Value ${rangeMax} is out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }

  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }
  return values;
}

function parseField(
  fieldStr: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (!fieldStr || fieldStr.trim() === "") {
    throw new Error(`Field "${fieldName}" is empty or blank`);
  }

  const segments = fieldStr.split(",");

  for (const segment of segments) {
    if (segment === "") {
      throw new Error(
        `Invalid field "${fieldName}": empty segment detected — check for leading, trailing, or consecutive commas in "${fieldStr}"`
      );
    }
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    for (const v of parseSegment(segment, min, max, fieldName)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string argument, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("parseCron received an empty or blank cron expression");
  }

  const fieldStrings = trimmed.split(/\s+/);

  if (fieldStrings.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected exactly 5 space-separated fields, got ${fieldStrings.length}. ` +
        `Required format: "minute hour dayOfMonth month dayOfWeek". Received: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(fieldStrings[i], min, max, name);
  }

  return result;
}

type FlatResult = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectRecursive(
  obj: Record<string, unknown>,
  prefix: string,
  result: FlatResult,
  visited: WeakSet<object>
): void {
  if (visited.has(obj)) {
    // Circular reference — silently skip to avoid infinite recursion
    return;
  }

  visited.add(obj);

  for (const key of Object.keys(obj)) {
    // Guard against inherited properties sneaking in (shouldn't happen with Object.keys, but be explicit)
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value)) {
      flattenObjectRecursive(value, fullKey, result, visited);
    } else {
      // Leaf value — could be primitive, array, Date, RegExp, null, undefined, etc.
      result[fullKey] = value;
    }
  }

  // Remove after processing so the same object can appear in multiple
  // non-circular branches (shared references) without being incorrectly skipped
  visited.delete(obj);
}

export default function flattenObject(input: Record<string, unknown>): FlatResult {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expected a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const result: FlatResult = {};
  flattenObjectRecursive(input, "", result, new WeakSet());
  return result;
}

class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new Error("Capacity must be a positive integer");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;

    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value as string;
      this.cache.delete(lruKey);
    }

    this.cache.set(key, value);
  }
}

export default LRUCache;

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError("First argument must be a function");
  }
  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError("Delay must be a non-negative finite number");
  }

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let hasPending = false;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;
    hasPending = true;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      hasPending = false;
      const argsToCall = pendingArgs!;
      pendingArgs = undefined;
      fn(...argsToCall);
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    hasPending = false;
    pendingArgs = undefined;
  };

  debounced.flush = function (): void {
    if (!hasPending) {
      return;
    }

    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }

    hasPending = false;
    const argsToCall = pendingArgs!;
    pendingArgs = undefined;
    fn(...argsToCall);
  };

  return debounced;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Readonly<Record<keyof CronResult, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: ReadonlyArray<keyof CronResult> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (value < range.min || value > range.max) {
    throw new Error(
      `Value ${value} is out of valid range [${range.min}, ${range.max}] in "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Expected an integer, got "${raw}" in "${context}"`);
  }
  const n = parseInt(raw, 10);
  if (isNaN(n)) {
    throw new Error(`Could not parse integer from "${raw}" in "${context}"`);
  }
  return n;
}

function expandRange(start: number, end: number, expr: string): number[] {
  if (start > end) {
    throw new Error(
      `Range start (${start}) must not exceed end (${end}) in "${expr}"`
    );
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, range: FieldRange): number[] {
  // Step: */n, start/n, start-end/n
  if (segment.includes("/")) {
    const parts = segment.split("/");
    if (parts.length !== 2) {
      throw new Error(`Invalid step expression: "${segment}"`);
    }
    const [baseExpr, stepRaw] = parts;
    const step = parseInteger(stepRaw, segment);
    if (step <= 0) {
      throw new Error(`Step must be a positive integer, got ${step} in "${segment}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (baseExpr === "*") {
      rangeStart = range.min;
      rangeEnd   = range.max;
    } else if (baseExpr.includes("-")) {
      const dashParts = baseExpr.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Invalid range in step expression: "${segment}"`);
      }
      rangeStart = parseInteger(dashParts[0], segment);
      rangeEnd   = parseInteger(dashParts[1], segment);
    } else {
      rangeStart = parseInteger(baseExpr, segment);
      rangeEnd   = range.max;
    }

    assertInRange(rangeStart, range, segment);
    assertInRange(rangeEnd,   range, segment);
    if (rangeStart > rangeEnd) {
      throw new Error(
        `Range start (${rangeStart}) must not exceed end (${rangeEnd}) in "${segment}"`
      );
    }

    const values: number[] = [];
    for (let v = rangeStart; v <= rangeEnd; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard: *
  if (segment === "*") {
    return Array.from(
      { length: range.max - range.min + 1 },
      (_, i) => range.min + i
    );
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Invalid range expression: "${segment}"`);
    }
    const start = parseInteger(dashParts[0], segment);
    const end   = parseInteger(dashParts[1], segment);
    assertInRange(start, range, segment);
    assertInRange(end,   range, segment);
    return expandRange(start, end, segment);
  }

  // Single number
  const n = parseInteger(segment, segment);
  assertInRange(n, range, segment);
  return [n];
}

function parseField(expr: string, range: FieldRange): number[] {
  if (!expr || expr.trim() === "") {
    throw new Error("Field expression must not be empty");
  }

  // Comma-separated list — each part is parsed independently
  if (expr.includes(",")) {
    const parts = expr.split(",");
    if (parts.some((p) => p.trim() === "")) {
      throw new Error(`Empty segment in comma list: "${expr}"`);
    }
    const seen = new Set<number>();
    for (const part of parts) {
      for (const v of parseSegment(part.trim(), range)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(expr, range);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${rawFields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const fieldExpr = rawFields[i];
    try {
      result[fieldName] = parseField(fieldExpr, FIELD_RANGES[fieldName]);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(
        `Invalid ${fieldName} field "${fieldExpr}" at position ${i + 1}: ${message}`
      );
    }
  }

  return result;
}

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInner(
  target: PlainObject,
  source: PlainObject,
  seen: WeakMap<object, PlainObject>
): PlainObject {
  if (seen.has(source)) {
    return seen.get(source)!;
  }

  const result: PlainObject = { ...target };
  seen.set(source, result);

  for (const key of Object.keys(source)) {
    if (UNSAFE_KEYS.has(key)) {
      continue;
    }

    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = mergeInner(targetVal, sourceVal, seen);
    } else if (sourceVal !== undefined) {
      result[key] = sourceVal;
    }
  }

  return result;
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`
    );
  }

  return mergeInner(target, source, new WeakMap()) as T & S;
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  function invoke(): void {
    if (pendingArgs !== null) {
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  }

  function cancel(): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  }

  function flush(): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    invoke();
  }

  function debounced(...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, delay);
  }

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      if (pendingArgs !== undefined) {
        fn(...pendingArgs);
        pendingArgs = undefined;
      }
      timerId = undefined;
    }, delay);
  };

  debounced.cancel = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    if (pendingArgs !== undefined) {
      const args = pendingArgs;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  return debounced as DebouncedFunction<T>;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else if (Array.isArray(value)) {
      result[fullKey] = JSON.stringify(value);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel head (oldest) and tail (newest) — never store real data,
  // so we never have to null-check neighbors of real nodes.
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "__head__", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "__tail__", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) return undefined;
    this.moveToTail(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache stores nothing — every write is a no-op.
    if (this.capacity === 0) return;

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToTail(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertBeforeTail(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  // ── private helpers ───────────────────────────────────────────────────────

  private unlink(node: Node<T>): void {
    // Safe because sentinels guarantee prev/next are never null for real nodes.
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertBeforeTail(node: Node<T>): void {
    const prev = this.tail.prev!;
    prev.next = node;
    node.prev = prev;
    node.next = this.tail;
    this.tail.prev = node;
  }

  private moveToTail(node: Node<T>): void {
    this.unlink(node);
    this.insertBeforeTail(node);
  }

  private evictLRU(): void {
    const lru = this.head.next!;
    // Guard: never evict the tail sentinel (would mean capacity is 0,
    // but that path is already blocked above).
    if (lru === this.tail) return;
    this.unlink(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [rangeStart, rangeEnd] = rangePart.split("-").map((n) => parseInt(n, 10));
        if (isNaN(rangeStart) || isNaN(rangeEnd)) {
          throw new Error(`Invalid range: ${rangePart}`);
        }
        start = rangeStart;
        end = rangeEnd;
      } else {
        start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new Error(`Invalid step base: ${rangePart}`);
        }
      }
    }

    validateRange(start, end, min, max, field);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }
    validateRange(start, end, min, max, field);
    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${field}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }
  return [value];
}

function validateRange(
  start: number,
  end: number,
  min: number,
  max: number,
  field: string
): void {
  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range in field: ${field}`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} is greater than end ${end} in field: ${field}`);
  }
  if (start < min || end > max) {
    throw new Error(
      `Range [${start}, ${end}] out of bounds [${min}, ${max}] in field: ${field}`
    );
  }
}

function parseCron(expression: string): CronFields {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max);
  }

  return result;
}

export default parseCron;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, readonly [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
} as const;

function parseNonNegativeInteger(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `Invalid token "${raw}" in field "${fieldName}": expected a non-negative integer`
    );
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isFinite(n) || n > 2_147_483_647) {
    throw new Error(
      `Value "${raw}" in field "${fieldName}" is out of acceptable bounds`
    );
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, fieldName: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} is out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

function expandExpression(
  expr: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const trimmed = expr.trim();

  if (!trimmed) {
    throw new Error(`Empty expression segment in field "${fieldName}"`);
  }

  // ---- step: base/step  (where base is *, num, or range) ----
  const slashIndex = trimmed.indexOf('/');
  if (slashIndex !== -1) {
    const basePart = trimmed.slice(0, slashIndex);
    const stepPart = trimmed.slice(slashIndex + 1);

    if (!basePart || !stepPart || stepPart.includes('/') || stepPart.includes('-')) {
      throw new Error(`Malformed step expression "${trimmed}" in field "${fieldName}"`);
    }

    const step = parseNonNegativeInteger(stepPart, fieldName);
    if (step === 0) {
      throw new Error(
        `Step value of 0 is invalid in field "${fieldName}" — would produce an infinite loop`
      );
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (basePart === '*') {
      rangeStart = min;
      rangeEnd   = max;
    } else if (basePart.includes('-')) {
      const dashIndex = basePart.indexOf('-');
      rangeStart = parseNonNegativeInteger(basePart.slice(0, dashIndex), fieldName);
      rangeEnd   = parseNonNegativeInteger(basePart.slice(dashIndex + 1), fieldName);
      assertInRange(rangeStart, min, max, fieldName);
      assertInRange(rangeEnd,   min, max, fieldName);
      if (rangeStart > rangeEnd) {
        throw new Error(
          `Range start ${rangeStart} exceeds end ${rangeEnd} in field "${fieldName}"`
        );
      }
    } else {
      // "5/3" — start at 5, walk to max
      rangeStart = parseNonNegativeInteger(basePart, fieldName);
      assertInRange(rangeStart, min, max, fieldName);
      rangeEnd = max;
    }

    const results: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      results.push(i);
    }
    return results;
  }

  // ---- wildcard ----
  if (trimmed === '*') {
    const results: number[] = [];
    for (let i = min; i <= max; i++) {
      results.push(i);
    }
    return results;
  }

  // ---- range: start-end ----
  const dashIndex = trimmed.indexOf('-');
  if (dashIndex !== -1) {
    const startStr = trimmed.slice(0, dashIndex);
    const endStr   = trimmed.slice(dashIndex + 1);

    if (!startStr || !endStr) {
      throw new Error(`Malformed range expression "${trimmed}" in field "${fieldName}"`);
    }

    const start = parseNonNegativeInteger(startStr, fieldName);
    const end   = parseNonNegativeInteger(endStr,   fieldName);
    assertInRange(start, min, max, fieldName);
    assertInRange(end,   min, max, fieldName);

    if (start > end) {
      throw new Error(
        `Range start ${start} exceeds end ${end} in field "${fieldName}"`
      );
    }

    const results: number[] = [];
    for (let i = start; i <= end; i++) {
      results.push(i);
    }
    return results;
  }

  // ---- single value ----
  const value = parseNonNegativeInteger(trimmed, fieldName);
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(raw: string, min: number, max: number, fieldName: string): number[] {
  if (!raw || !raw.trim()) {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  const parts = raw.split(',');
  const seen  = new Set<number>();

  for (const part of parts) {
    if (!part.trim()) {
      throw new Error(
        `Empty element in comma-separated list for field "${fieldName}" — check for trailing commas`
      );
    }
    for (const value of expandExpression(part, min, max, fieldName)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (expression === null || expression === undefined) {
    throw new Error('Cron expression must not be null or undefined');
  }
  if (typeof expression !== 'string') {
    throw new TypeError(
      `Cron expression must be a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error('Cron expression must not be empty or whitespace-only');
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 space-separated fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, ...FIELD_RANGES.minute,     'minute'),
    hour:       parseField(hourRaw,   ...FIELD_RANGES.hour,       'hour'),
    dayOfMonth: parseField(domRaw,    ...FIELD_RANGES.dayOfMonth, 'dayOfMonth'),
    month:      parseField(monthRaw,  ...FIELD_RANGES.month,      'month'),
    dayOfWeek:  parseField(dowRaw,    ...FIELD_RANGES.dayOfWeek,  'dayOfWeek'),
  };
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      if (pendingArgs !== null) {
        fn(...pendingArgs);
        pendingArgs = null;
      }
      timerId = null;
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    if (pendingArgs !== null) {
      fn(...pendingArgs);
      pendingArgs = null;
    }
  };

  return debounced;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(val: unknown): val is PlainObject {
  if (typeof val !== "object" || val === null) return false;
  const proto = Object.getPrototypeOf(val);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakSet<object>
): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    if (seen.has(source as object)) {
      // Circular reference in source — return target unchanged to avoid infinite loop
      return target;
    }
    seen.add(source as object);

    const result: PlainObject = Object.assign({}, target);

    for (const key of Object.keys(source)) {
      if (!Object.prototype.hasOwnProperty.call(source, key)) continue;
      result[key] = mergeInternal(result[key], source[key], seen);
    }

    return result;
  }

  // Primitives, class instances, mismatched types: source wins
  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: target must be a plain object, got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: source must be a plain object, got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInternal(target, source, new WeakSet()) as T & S;
}

interface DLinkedNode<T> {
  key: string;
  value: T;
  prev: DLinkedNode<T> | null;
  next: DLinkedNode<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, DLinkedNode<T>>;
  // Sentinel head (most-recent side) and tail (least-recent side)
  private readonly head: DLinkedNode<T>;
  private readonly tail: DLinkedNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    if (capacity < 0) {
      throw new RangeError(`Capacity must be non-negative, got: ${capacity}`);
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes — never hold real data, just bookend the list
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache — silently accept but never store
    if (this.capacity === 0) {
      return;
    }

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: DLinkedNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  // ── Private helpers ────────────────────────────────────────────────────────

  private insertAtFront(node: DLinkedNode<T>): void {
    node.prev = this.head;
    node.next = this.head.next;
    // head.next is always non-null (at worst it's the tail sentinel)
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: DLinkedNode<T>): void {
    // Both neighbours are guaranteed non-null because sentinels bookend the list
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: DLinkedNode<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;
    // Guard: lru should never be the head sentinel while map.size > 0,
    // but be defensive in case of unexpected state corruption.
    if (lru === null || lru === this.head) {
      return;
    }
    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private head: Node<T> | null; // most recently used
  private tail: Node<T> | null; // least recently used

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) return undefined;
    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (this.capacity === 0) return;

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    if (this.map.size >= this.capacity) {
      this.evictTail();
    }

    const node: Node<T> = { key, value, prev: null, next: this.head };
    if (this.head !== null) {
      this.head.prev = node;
    }
    this.head = node;
    if (this.tail === null) {
      this.tail = node;
    }
    this.map.set(key, node);
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return;

    // Detach from current position
    if (node.prev !== null) {
      node.prev.next = node.next;
    }
    if (node.next !== null) {
      node.next.prev = node.prev;
    }
    if (node === this.tail) {
      this.tail = node.prev;
    }

    // Re-attach at head
    node.prev = null;
    node.next = this.head;
    if (this.head !== null) {
      this.head.prev = node;
    }
    this.head = node;
  }

  private evictTail(): void {
    if (this.tail === null) return;

    this.map.delete(this.tail.key);

    if (this.tail.prev !== null) {
      this.tail.prev.next = null;
      this.tail = this.tail.prev;
    } else {
      // Only one node existed
      this.head = null;
      this.tail = null;
    }
  }
}

type AnyFunction = (...args: never[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): ReturnType<T> | undefined;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number,
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  const resolvedDelay = Number.isFinite(delay) && delay >= 0 ? delay : 0;

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  function invokePending(): ReturnType<T> {
    // Capture and clear before calling to prevent re-entrancy issues
    const args = pendingArgs as Parameters<T>;
    pendingArgs = undefined;
    return fn(...(args as Parameters<T>)) as ReturnType<T>;
  }

  function debounced(...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      // pendingArgs may have been cleared by cancel() or flush() before
      // the timer fires — guard against that
      if (pendingArgs !== undefined) {
        invokePending();
      }
    }, resolvedDelay);
  }

  debounced.cancel = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = function (): ReturnType<T> | undefined {
    // Nothing is pending — no-op
    if (timerId === undefined || pendingArgs === undefined) {
      return undefined;
    }

    clearTimeout(timerId);
    timerId = undefined;

    return invokePending();
  };

  return debounced;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseField(field: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = parts.flatMap((part) => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */n or start/n or start-end/n
  if (field.includes("/")) {
    const [left, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step value: ${stepStr}`);
    }

    let from: number;
    let to: number;

    if (left === "*") {
      from = min;
      to = max;
    } else if (left.includes("-")) {
      const [startStr, endStr] = left.split("-");
      from = clamp(parseInt(startStr, 10), min, max);
      to = clamp(parseInt(endStr, 10), min, max);
    } else {
      from = clamp(parseInt(left, 10), min, max);
      to = max;
    }

    const values: number[] = [];
    for (let i = from; i <= to; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const from = clamp(parseInt(startStr, 10), min, max);
    const to = clamp(parseInt(endStr, 10), min, max);
    return range(from, to);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new TypeError(`Invalid cron field value: "${field}"`);
  }
  return [clamp(value, min, max)];
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Normalize 7 (Sunday) to 0
  const normalized = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(normalized)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldNames = Object.keys(FIELD_CONFIGS) as Array<keyof CronResult>;

  const rawValues = [minuteField, hourField, domField, monthField, dowField].map(
    (field, index) => parseField(field, FIELD_CONFIGS[fieldNames[index]])
  );

  return {
    minute: rawValues[0],
    hour: rawValues[1],
    dayOfMonth: rawValues[2],
    month: rawValues[3],
    dayOfWeek: normalizeDayOfWeek(rawValues[4]),
  };
}

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: PlainObject,
  source: PlainObject,
  seen: WeakMap<object, PlainObject>
): PlainObject {
  if (seen.has(source)) {
    // Return already-merged result to break circular reference cycle
    return seen.get(source)!;
  }

  const result: PlainObject = Object.assign(Object.create(null), target);
  seen.set(source, result);

  for (const key of Object.keys(source)) {
    // Guard against prototype pollution attacks
    if (UNSAFE_KEYS.has(key)) continue;

    const srcVal = source[key];
    const tgtVal = result[key];

    if (srcVal === undefined) {
      // Never let an explicit undefined silently erase a real target value
      continue;
    }

    if (Array.isArray(srcVal) && Array.isArray(tgtVal)) {
      // Concatenate arrays; freeze-in a copy so callers can't mutate our internals
      result[key] = [...tgtVal, ...srcVal];
    } else if (isPlainObject(srcVal) && isPlainObject(tgtVal)) {
      result[key] = mergeInternal(tgtVal, srcVal, seen);
    } else {
      // Scalar, Date, RegExp, Map, Set, null, mismatched types — source wins
      result[key] = srcVal;
    }
  }

  return result;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: 'target' must be a plain object, got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: 'source' must be a plain object, got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInternal(target, source, new WeakMap()) as T & S;
}

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, object>
): unknown {
  // source undefined → preserve target (avoid erasing existing values)
  if (source === undefined) return target;

  // Both arrays → concatenate (shallow; elements are not deep-merged)
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  // Both plain objects → recursive merge
  if (isPlainObject(target) && isPlainObject(source)) {
    // Guard against circular references in source
    const cached = seen.get(source as object);
    if (cached !== undefined) return cached;

    // Spread target first so own-enumerable keys are copied
    const result: PlainObject = { ...target };

    // Register before recursing so back-references resolve to this object
    seen.set(source as object, result);

    for (const key of Object.keys(source)) {
      // Prototype-pollution guard
      if (UNSAFE_KEYS.has(key)) continue;
      result[key] = mergeInternal(target[key], source[key], seen);
    }

    return result;
  }

  // Primitive, class instance, mixed array/object, etc. → source wins
  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  return mergeInternal(target, source, new WeakMap()) as T & S;
}

type Scalar = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedValue = Scalar | Date | RegExp | Function | unknown[];

export type FlattenedObject = Record<string, FlattenedValue>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInto(
  obj: Record<string, unknown>,
  prefix: string,
  result: FlattenedObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at path "${prefix || "<root>"}"`
    );
  }

  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    // Guard against prototype pollution — Object.keys should already exclude
    // non-own properties, but be explicit about __proto__ and constructor.
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const value = obj[key];
    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      // Recurse into plain objects. Empty plain objects ({}) are deliberately
      // omitted — they carry no scalar data to flatten into a leaf entry.
      if (Object.keys(value).length > 0) {
        flattenInto(value, flatKey, result, ancestors);
      }
    } else {
      result[flatKey] = value as FlattenedValue;
    }
  }

  // Backtrack so that the same object reference appearing at a *different*
  // (non-circular) path is still processed correctly.
  ancestors.delete(obj);
}

function flattenObject(
  obj: Record<string, unknown>
): FlattenedObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlattenedObject = {};
  flattenInto(obj, "", result, new WeakSet());
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? (JSON.stringify(value) as unknown as Primitive)
        : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<keyof CronExpression, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new Error(`Value ${value} is out of valid range [${min}, ${max}] in: "${context}"`);
  }
}

function parseRange(raw: string, fieldMin: number, fieldMax: number): [number, number] {
  const parts = raw.split('-');
  if (parts.length !== 2 || parts[0] === '' || parts[1] === '') {
    throw new Error(`Malformed range expression: "${raw}"`);
  }
  const start = parseInt(parts[0], 10);
  const end   = parseInt(parts[1], 10);
  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Non-numeric range bounds in: "${raw}"`);
  }
  if (start > end) {
    throw new Error(`Range start (${start}) exceeds end (${end}) in: "${raw}"`);
  }
  assertInRange(start, fieldMin, fieldMax, raw);
  assertInRange(end,   fieldMin, fieldMax, raw);
  return [start, end];
}

function expandStep(raw: string, fieldMin: number, fieldMax: number): number[] {
  const slashParts = raw.split('/');
  if (slashParts.length !== 2 || slashParts[0] === '' || slashParts[1] === '') {
    throw new Error(`Malformed step expression: "${raw}"`);
  }

  const [baseStr, stepStr] = slashParts;
  const step = parseInt(stepStr, 10);
  if (isNaN(step) || step <= 0) {
    throw new Error(`Step value must be a positive integer in: "${raw}"`);
  }

  let rangeMin = fieldMin;
  let rangeMax = fieldMax;

  if (baseStr === '*') {
    rangeMin = fieldMin;
    rangeMax = fieldMax;
  } else if (baseStr.includes('-')) {
    [rangeMin, rangeMax] = parseRange(baseStr, fieldMin, fieldMax);
  } else {
    const start = parseInt(baseStr, 10);
    if (isNaN(start)) {
      throw new Error(`Non-numeric base in step expression: "${raw}"`);
    }
    assertInRange(start, fieldMin, fieldMax, raw);
    rangeMin = start;
    rangeMax = fieldMax;
  }

  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }
  if (values.length === 0) {
    throw new Error(`Step expression "${raw}" produces no valid values`);
  }
  return values;
}

function parseAtom(raw: string, fieldMin: number, fieldMax: number): number[] {
  if (raw === '') {
    throw new Error('Empty atom in cron field');
  }

  if (raw === '*') {
    return Array.from({ length: fieldMax - fieldMin + 1 }, (_, i) => fieldMin + i);
  }

  if (raw.includes('/')) {
    return expandStep(raw, fieldMin, fieldMax);
  }

  if (raw.includes('-')) {
    const [start, end] = parseRange(raw, fieldMin, fieldMax);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  const value = parseInt(raw, 10);
  if (isNaN(value) || String(value) !== raw.trim()) {
    throw new Error(`Invalid numeric token: "${raw}"`);
  }
  assertInRange(value, fieldMin, fieldMax, raw);
  return [value];
}

function parseField(raw: string, fieldMin: number, fieldMax: number): number[] {
  if (raw === '' || raw.trim() === '') {
    throw new Error('Field must not be empty');
  }

  const atoms = raw.split(',');
  if (atoms.some(a => a === '')) {
    throw new Error(`Trailing, leading, or consecutive commas in field: "${raw}"`);
  }

  const seen = new Set<number>();
  for (const atom of atoms) {
    for (const v of parseAtom(atom.trim(), fieldMin, fieldMax)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (expression == null || typeof expression !== 'string') {
    throw new TypeError('Cron expression must be a non-null string');
  }

  const trimmed = expression.trim();
  if (trimmed === '') {
    throw new Error('Cron expression must not be blank');
  }

  // Guard against pathologically large inputs before splitting
  if (trimmed.length > 256) {
    throw new Error('Cron expression exceeds maximum allowed length (256 chars)');
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${trimmed}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];
  const result = {} as CronExpression;

  for (let i = 0; i < fieldNames.length; i++) {
    const name   = fieldNames[i];
    const raw    = fields[i];
    const { min, max } = FIELD_RANGES[name];

    try {
      result[name] = parseField(raw, min, max);
    } catch (err) {
      throw new Error(
        `Invalid ${name} field ("${raw}"): ${(err as Error).message}`
      );
    }
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (source === undefined) {
    return target;
  }

  return source;
}

export default deepMerge;

type AnyFunction = (...args: any[]) => any;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): ReturnType<T> | undefined;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number,
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`debounce: expected a function, got ${typeof fn}`);
  }

  const safeDelay = Number.isFinite(delay) && delay >= 0 ? Math.floor(delay) : 0;

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;
  let pendingContext: unknown = undefined;

  const cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
    pendingContext = undefined;
  };

  const flush = (): ReturnType<T> | undefined => {
    if (pendingArgs === null) {
      return undefined;
    }
    const args = pendingArgs;
    const ctx = pendingContext;
    cancel(); // clear timer and state before invoking to prevent re-entrancy issues
    return fn.apply(ctx, args) as ReturnType<T>;
  };

  function debounced(this: unknown, ...args: Parameters<T>): void {
    pendingArgs = args;
    pendingContext = this;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const args = pendingArgs;
      const ctx = pendingContext;
      pendingArgs = null;
      pendingContext = undefined;
      if (args !== null) {
        fn.apply(ctx, args);
      }
    }, safeDelay);
  }

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced as DebouncedFunction<T>;
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key) as T;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value as string;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInternal(
  obj: object,
  prefix: string,
  seen: Set<object>,
  result: FlatObject
): void {
  // Detect cycles — same reference appearing in its own ancestor chain
  if (seen.has(obj)) {
    throw new Error(`Circular reference detected at path: "${prefix}"`);
  }
  seen.add(obj);

  const entries: [string, unknown][] = Array.isArray(obj)
    ? obj.map((v, i) => [String(i), v])
    : (Object.entries(obj) as [string, unknown][]);

  for (const [key, value] of entries) {
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (Array.isArray(value)) {
      // Empty arrays have no children to descend into — preserve as leaf
      if (value.length === 0) {
        result[fullKey] = value;
      } else {
        flattenInternal(value, fullKey, seen, result);
      }
    } else if (isPlainObject(value)) {
      // Empty objects have no children to descend into — preserve as leaf
      if (Object.keys(value).length === 0) {
        result[fullKey] = value;
      } else {
        flattenInternal(value, fullKey, seen, result);
      }
    } else {
      // Leaf: primitives, null, Date, RegExp, Map, Set, etc.
      result[fullKey] = value;
    }
  }

  // Remove from seen after processing so diamond-shaped (non-cyclic) references
  // to the same object from different branches are allowed
  seen.delete(obj);
}

export default function flattenObject(obj: Record<string, unknown>): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flattenInternal(obj, "", new Set<object>(), result);
  return result;
}

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  if (!Number.isFinite(delay) || delay < 0) {
    throw new RangeError(`Expected a non-negative finite number for delay, got ${delay}`);
  }

  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const invoke = (): void => {
    if (pendingArgs === null) return;
    const argsToCall = pendingArgs;
    pendingArgs = null;
    timerId = null;
    fn(...argsToCall);
  };

  const cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  const flush = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    invoke();
  };

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(invoke, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // head = most recently used, tail = least recently used
  private head: Node<T> | null;
  private tail: Node<T> | null;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();
    this.head = null;
    this.tail = null;
  }

  get(key: string): T | undefined {
    if (key === undefined || key === null) return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.moveToHead(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (key === undefined || key === null) {
      throw new TypeError(`LRUCache key must not be null or undefined`);
    }
    if (value === undefined) {
      throw new TypeError(
        `LRUCache value must not be undefined — use delete() to remove an entry`
      );
    }

    // Zero-capacity cache: accept writes but never retain anything
    if (this.capacity === 0) return;

    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToHead(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtHead(node);

    if (this.map.size > this.capacity) {
      this.evictTail();
    }
  }

  get size(): number {
    return this.map.size;
  }

  // ── private helpers ──────────────────────────────────────────────────────

  private insertAtHead(node: Node<T>): void {
    node.prev = null;
    node.next = this.head;

    if (this.head !== null) {
      this.head.prev = node;
    }

    this.head = node;

    if (this.tail === null) {
      this.tail = node;
    }
  }

  private removeNode(node: Node<T>): void {
    if (node.prev !== null) {
      node.prev.next = node.next;
    } else {
      // node is head
      this.head = node.next;
    }

    if (node.next !== null) {
      node.next.prev = node.prev;
    } else {
      // node is tail
      this.tail = node.prev;
    }

    node.prev = null;
    node.next = null;
  }

  private moveToHead(node: Node<T>): void {
    if (node === this.head) return; // already most-recently used
    this.removeNode(node);
    this.insertAtHead(node);
  }

  private evictTail(): void {
    if (this.tail === null) return; // nothing to evict — should never happen

    const evicted = this.tail;
    this.removeNode(evicted);
    this.map.delete(evicted.key);
  }
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint | Function;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };

function isTraversable(val: unknown): val is NestedObject {
  if (val === null || typeof val !== "object" || Array.isArray(val)) return false;
  const proto = Object.getPrototypeOf(val);
  // Only traverse plain objects — not Date, RegExp, Map, Set, etc.
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  obj: NestedObject,
  prefix = "",
  seen = new WeakSet<object>()
): Record<string, unknown> {
  if (obj === null || typeof obj !== "object") {
    throw new TypeError(`Expected a plain object, got ${obj === null ? "null" : typeof obj}`);
  }

  if (seen.has(obj)) {
    throw new Error(
      `Circular reference detected${prefix ? ` at path "${prefix}"` : " at root"}`
    );
  }

  seen.add(obj);
  const result: Record<string, unknown> = {};

  for (const key of Object.keys(obj)) {
    // Guard against prototype pollution via inherited keys (Object.keys is own-only, but be explicit)
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = (obj as Record<string, unknown>)[key];

    if (isTraversable(value)) {
      if (Object.keys(value).length === 0) {
        // Empty plain object — emit as leaf to preserve information
        result[fullKey] = value;
      } else {
        Object.assign(result, flattenObject(value, fullKey, seen));
      }
    } else {
      result[fullKey] = value;
    }
  }

  // Remove after processing so the same object reference may legally appear
  // in sibling branches without being mistaken for a circular reference.
  seen.delete(obj);

  return result;
}

export default flattenObject;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
  readonly name: string;
}

const FIELD_CONFIGS = {
  minute:     { min: 0,  max: 59, name: "minute"     },
  hour:       { min: 0,  max: 23, name: "hour"        },
  dayOfMonth: { min: 1,  max: 31, name: "dayOfMonth"  },
  month:      { min: 1,  max: 12, name: "month"       },
  dayOfWeek:  { min: 0,  max: 6,  name: "dayOfWeek"   },
} as const satisfies Record<keyof CronExpression, FieldConfig>;

function strictParseInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new Error(`Invalid integer "${raw}" in ${context}`);
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow "${raw}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${config.min}–${config.max}] for field "${config.name}"`
    );
  }
}

function buildRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function parseRangeToken(token: string, config: FieldConfig): [number, number] {
  const parts = token.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range token "${token}" in field "${config.name}": expected exactly one "-"`);
  }
  const start = strictParseInt(parts[0], `field "${config.name}"`);
  const end   = strictParseInt(parts[1], `field "${config.name}"`);
  assertInRange(start, config);
  assertInRange(end, config);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${config.name}"`
    );
  }
  return [start, end];
}

function parseToken(token: string, config: FieldConfig): number[] {
  if (token.trim() === "") {
    throw new Error(`Empty token encountered in field "${config.name}"`);
  }

  // Step value: base/step — e.g. "*/15" or "1-30/5" or "0/5"
  if (token.includes("/")) {
    const slashParts = token.split("/");
    if (slashParts.length !== 2) {
      throw new Error(
        `Invalid step expression "${token}" in field "${config.name}": expected exactly one "/"`
      );
    }
    const [base, stepStr] = slashParts;
    const step = strictParseInt(stepStr, `step in field "${config.name}"`);
    if (step < 1) {
      throw new RangeError(`Step value must be ≥ 1, got ${step} in field "${config.name}"`);
    }

    let start: number;
    let end: number;

    if (base === "*") {
      start = config.min;
      end   = config.max;
    } else if (base.includes("-")) {
      [start, end] = parseRangeToken(base, config);
    } else {
      start = strictParseInt(base, `step base in field "${config.name}"`);
      assertInRange(start, config);
      end = config.max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (token === "*") {
    return buildRange(config.min, config.max);
  }

  // Range: "N-M"
  if (token.includes("-")) {
    const [start, end] = parseRangeToken(token, config);
    return buildRange(start, end);
  }

  // Single number
  const value = strictParseInt(token, `field "${config.name}"`);
  assertInRange(value, config);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (!raw || raw.trim() === "") {
    throw new Error(`Field "${config.name}" is empty`);
  }

  const allValues: number[] = [];

  // Comma-separated list — each part is parsed independently (no nested commas)
  const parts = raw.split(",");
  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new Error(
        `Empty segment in comma-separated field "${config.name}" (raw: "${raw}")`
      );
    }
    if (trimmed.includes(",")) {
      // Shouldn't reach here after split, but guard anyway
      throw new Error(`Unexpected nested comma in field "${config.name}"`);
    }
    const values = parseToken(trimmed, config);
    allValues.push(...values);
  }

  // Deduplicate and sort ascending
  const unique = [...new Set(allValues)].sort((a, b) => a - b);

  if (unique.length === 0) {
    throw new Error(`Field "${config.name}" produced no valid values from expression "${raw}"`);
  }

  return unique;
}

export default function parseCron(expression: string): CronExpression {
  if (expression === null || expression === undefined) {
    throw new TypeError("Cron expression must be a non-null string");
  }
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty or whitespace-only");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = fields;

  return {
    minute:     parseField(minuteRaw,     FIELD_CONFIGS.minute),
    hour:       parseField(hourRaw,       FIELD_CONFIGS.hour),
    dayOfMonth: parseField(dayOfMonthRaw, FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthRaw,      FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dayOfWeekRaw,  FIELD_CONFIGS.dayOfWeek),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const invoke = () => {
    if (pendingArgs !== null) {
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;
    if (timerId !== null) {
      clearTimeout(timerId);
    }
    timerId = setTimeout(() => {
      timerId = null;
      invoke();
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    invoke();
  };

  return debounced;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      result[key] = key in result
        ? deepMerge(result[key], source[key])
        : source[key];
    }

    return result;
  }

  return source === undefined ? target : source;
}

export default deepMerge;

type AnyFunction = (...args: any[]) => any;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number,
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }

  const safeDelay = Math.max(0, Number.isFinite(delay) ? delay : 0);

  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;
  let pendingContext: unknown;

  function invoke(): void {
    // Snapshot and clear state *before* calling fn so that if fn itself
    // triggers the debounced function, state is consistent.
    if (pendingArgs === undefined) return;
    const args = pendingArgs;
    const ctx = pendingContext;
    pendingArgs = undefined;
    pendingContext = undefined;
    fn.apply(ctx, args);
  }

  function cancel(): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
    pendingContext = undefined;
  }

  function flush(): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    // invoke is a no-op when nothing is pending
    invoke();
  }

  function debounced(this: unknown, ...args: Parameters<T>): void {
    pendingArgs = args;
    pendingContext = this;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      invoke();
    }, safeDelay);
  }

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

class LRUCache<T> {
  private capacity: number;
  private cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      const lruKey = this.cache.keys().next().value as string;
      this.cache.delete(lruKey);
    }
    this.cache.set(key, value);
  }
}

export default LRUCache;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInternal(
  obj: PlainObject,
  prefix: string,
  ancestors: WeakSet<object>
): Record<string, unknown> {
  const result: Record<string, unknown> = {};
  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value) && !ancestors.has(value)) {
      if (Object.keys(value).length === 0) {
        // Preserve empty objects as leaf values — flattening them would silently
        // swallow the key, making the output lossy and confusing to reconstruct.
        result[fullKey] = value;
      } else {
        Object.assign(result, flattenInternal(value, fullKey, ancestors));
      }
    } else {
      // Leaf cases: primitives, arrays, Dates, RegExps, null,
      // circular-reference objects (already in ancestors), and anything
      // that is not a plain object — all preserved verbatim.
      result[fullKey] = value;
    }
  }

  // Remove on the way back up so the same object can appear at a
  // different, non-ancestor path without being mistaken for a cycle.
  ancestors.delete(obj);
  return result;
}

export default function flattenObject(input: unknown): Record<string, unknown> {
  if (input === null || input === undefined) {
    return {};
  }
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received ${
        Array.isArray(input) ? "array" : typeof input
      }`
    );
  }
  return flattenInternal(input, "", new WeakSet<object>());
}

type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      assertInRange(s, min, max, fieldName);
      assertInRange(e, min, max, fieldName);
      if (s > e) throw new Error(`Invalid range "${rangePart}" in field "${fieldName}"`);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      assertInRange(start, min, max, fieldName);
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    if (start > end) throw new Error(`Invalid range "${segment}" in field "${fieldName}"`);
    return range(start, end);
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  const segments = field.split(",");
  const values = segments.flatMap((seg) => parseSegment(seg.trim(), min, max, fieldName));
  const result = unique(values);

  // Normalize dayOfWeek: treat 7 as 0 (both are Sunday)
  if (fieldName === "dayOfWeek") {
    const normalized = unique(result.map((v) => (v === 7 ? 0 : v)));
    return normalized;
  }

  return result;
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  return {
    minute: parseField(minuteField, ...FIELD_RANGES.minute, fieldNames[0]),
    hour: parseField(hourField, ...FIELD_RANGES.hour, fieldNames[1]),
    dayOfMonth: parseField(domField, ...FIELD_RANGES.dayOfMonth, fieldNames[2]),
    month: parseField(monthField, ...FIELD_RANGES.month, fieldNames[3]),
    dayOfWeek: parseField(dowField, ...FIELD_RANGES.dayOfWeek, fieldNames[4]),
  };
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }

    if (isNaN(start) || isNaN(end) || start < min || end > max || start > end) {
      throw new Error(`Invalid range "${rangePart}" for step expression`);
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: "${segment}"`);
    }
    if (start < min || end > max || start > end) {
      throw new Error(
        `Range "${segment}" out of bounds [${min}-${max}]`
      );
    }

    return range(start, end);
  }

  // Number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value: "${segment}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  }

  return [value];
};

const parseField = (field: string, config: FieldConfig): number[] => {
  if (field.includes(",")) {
    const segments = field.split(",");
    const values = new Set<number>();

    for (const segment of segments) {
      for (const value of parseSegment(segment.trim(), config)) {
        values.add(value);
      }
    }

    return Array.from(values).sort((a, b) => a - b);
  }

  return parseSegment(field, config);
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const keys = Object.keys(FIELD_CONFIGS) as (keyof CronResult)[];
  const rawFields = [minuteField, hourField, domField, monthField, dowField];

  const result = {} as CronResult;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    try {
      result[key] = parseField(rawFields[i], FIELD_CONFIGS[key]);
    } catch (err) {
      throw new Error(
        `Invalid cron field "${key}" with value "${rawFields[i]}": ${(err as Error).message}`
      );
    }
  }

  return result;
};

export default parseCron;

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = Math.floor(capacity);
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key) as T;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value as string;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

interface LRUNode<T> {
  key: string;
  value: T;
  prev: LRUNode<T> | null;
  next: LRUNode<T> | null;
}

export class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, LRUNode<T>>;
  // Sentinel head = most-recently-used side; sentinel tail = least-recently-used side.
  // Using sentinels eliminates null-pointer edge cases on insert/remove.
  private readonly head: LRUNode<T>;
  private readonly tail: LRUNode<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0 || !Number.isFinite(capacity)) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative finite integer, received: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes — values never externally observable; cast is safe here.
    this.head = { key: "__head__", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "__tail__", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    if (typeof key !== "string") return undefined;

    const node = this.map.get(key);
    if (node === undefined) return undefined;

    this.promoteToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    if (typeof key !== "string") {
      throw new TypeError(`LRUCache keys must be strings, received: ${typeof key}`);
    }

    // Zero-capacity cache: writes are silently dropped — nothing can ever be stored.
    if (this.capacity === 0) return;

    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.promoteToFront(existing);
      return;
    }

    // Evict the least-recently-used entry before inserting a new one.
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev;
      // Guard: should be structurally impossible with correct sentinel setup, but
      // be explicit rather than risk a silent null-dereference.
      if (lru === null || lru === this.head) {
        throw new Error("LRUCache internal invariant violated: LRU node is missing.");
      }
      this.detachNode(lru);
      this.map.delete(lru.key);
    }

    const node: LRUNode<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.attachAfterHead(node);
  }

  get size(): number {
    return this.map.size;
  }

  private promoteToFront(node: LRUNode<T>): void {
    this.detachNode(node);
    this.attachAfterHead(node);
  }

  private detachNode(node: LRUNode<T>): void {
    // Sentinels guarantee prev/next are never null for real nodes.
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private attachAfterHead(node: LRUNode<T>): void {
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next!.prev = node;
    this.head.next = node;
  }
}

export default LRUCache;
